CREATE   FUNCTION [dbo].[get_UPSACHNoProtocol_data]
(
    @p_start_date DATETIME,
    @p_end_date DATETIME
)
RETURNS TABLE 
AS
RETURN 
(
    SELECT 
        m.id as MachineId,
        m.name as MachineName,
        COALESCE(s.valuehourup, 0) AS uphour,
        s.countup,
        s.countupsucces,
        s.countupinterrupted,
        s.countcyclesup,
        COALESCE(s.valuehoursubup, 0) as subuphour,
        s.countsubroutineup,
        s.countcyclessubroutineup,
        s.countsubroutineupsucces,
        s.countsubroutineupinterrupted
    FROM
        Machine m
    LEFT JOIN (
        SELECT 
            MachineID, 
            SUM(IIF(oe.parentid is null, DATEDIFF(SECOND, oe.DtStart, oe.DtEnd) / 3600.00, 0)) AS valuehourup,
            COUNT(DISTINCT CASE WHEN oe.parentid is null THEN CAST(oe.id AS int) END) as countcyclesup,
            COUNT(DISTINCT CASE WHEN oe.parentid is null THEN oe.NameUP END) as countup,
            SUM(CAST(IIF(oe.ExecutionUpStatusTypeId = 1 and oe.parentid is null, 1, 0) AS int)) as countupsucces,
            SUM(CAST(IIF(oe.ExecutionUpStatusTypeId = 2 and oe.parentid is null, 1, 0) AS int)) as countupinterrupted,
            COUNT(DISTINCT CASE WHEN oe.parentid is not null THEN CAST(oe.id AS int) END) as countcyclessubroutineup,
            SUM(IIF(oe.parentid is not null, DATEDIFF(SECOND, oe.DtStart, oe.DtEnd) / 3600.00, 0)) AS valuehoursubup,
            COUNT(DISTINCT CASE WHEN oe.parentid is not null THEN oe.NameUP END) as countsubroutineup,
            SUM(CAST(IIF(oe.ExecutionUpStatusTypeId = 1 and oe.parentid is not null, 1, 0) AS int)) as countsubroutineupsucces,
            SUM(CAST(IIF(oe.ExecutionUpStatusTypeId = 2 and oe.parentid is not null, 1, 0) AS int)) as countsubroutineupinterrupted
        FROM 
            OperatingProgramExecutionLog oe
        WHERE
            oe.DtStart >= @p_start_date 
            AND oe.DtStart <= @p_end_date
        GROUP BY 
            oe.MachineID
        HAVING 
            SUM(DATEDIFF(SECOND, oe.DtStart, oe.DtEnd) / 3600.00) <> 0
    ) AS s
    ON 
        s.MachineID = m.id
    WHERE   
        m.isHide = 0 
        AND m.MonitoringPointTypeId in (0,2,3)
)
GO
