CREATE   FUNCTION [dbo].[get_MachineParamPercentSACH_data]
(
    @p_start_date DATETIME,
    @p_end_date DATETIME
)
RETURNS TABLE 
AS
RETURN 
(
    SELECT 
        MachineParamName,
        CAST((SUM(IIF(countdays = 0 OR countdays IS NULL, 0, 1)) * 1.00) / (COUNT(MachineName) * 1.00) AS NUMERIC(18,2)) as PercentParam,
        SUM(IIF(countdays = 0 OR countdays IS NULL, 0, 1)) as UseMachineCount,
        COUNT(MachineName) as TotalMachineCount
    FROM [dbo].[get_MonitoringSACHNoProtocol_data](@p_start_date, @p_end_date)
    GROUP BY MachineParamName
)
