---Ďđîöĺíň ďî ńňŕíęŕě ń ďđîňîęîëŕěč

CREATE   FUNCTION [dbo].[get_MachinePercentSACHProtocol_data]
(
    @p_start_date DATETIME,
    @p_end_date DATETIME
)
RETURNS TABLE 
AS
RETURN 
(
    SELECT 
        m.ShortName,
        CASE 
            WHEN mpp.MachineProtocolTypeID = 0 THEN 'íĺčçâĺńňíűé ďđîňîęîë'
            WHEN mpp.MachineProtocolTypeID = 1 THEN 'ŇÂÂ'
            WHEN mpp.MachineProtocolTypeID = 2 THEN 'Đ-16'
            WHEN mpp.MachineProtocolTypeID = 3 THEN 'ŇĐ'
            WHEN mpp.MachineProtocolTypeID = 4 THEN 'ŇĐ-1'
            WHEN mpp.MachineProtocolTypeID = 8 THEN 'Áŕëň-Ńčńňĺě'
            WHEN mpp.MachineProtocolTypeID = 9 THEN 'Đ-32'
            WHEN mpp.MachineProtocolTypeID = 10 THEN 'ŇÂÂ-10'
            WHEN mpp.MachineProtocolTypeID = 11 THEN 'Fanuc'
            WHEN mpp.MachineProtocolTypeID = 12 THEN 'TCP-64'
            WHEN mpp.MachineProtocolTypeID = 13 THEN 'Ěŕ˙ę'
            WHEN mpp.MachineProtocolTypeID = 14 THEN 'Heidenhain'
            WHEN mpp.MachineProtocolTypeID = 15 THEN 'ÂŃ-357'
            WHEN mpp.MachineProtocolTypeID = 16 THEN 'MTConnect'
            WHEN mpp.MachineProtocolTypeID = 17 THEN 'IFMVSXXX'
            WHEN mpp.MachineProtocolTypeID = 18 THEN 'Siemens PLC'
            WHEN mpp.MachineProtocolTypeID = 19 THEN 'Heidennain2'
            WHEN mpp.MachineProtocolTypeID = 20 THEN 'HAAS'
            WHEN mpp.MachineProtocolTypeID = 21 THEN 'Mitsubishi'
            WHEN mpp.MachineProtocolTypeID = 22 THEN 'SKFIMx'
            WHEN mpp.MachineProtocolTypeID = 23 THEN 'Universal'
            WHEN mpp.MachineProtocolTypeID = 24 THEN 'OPCUA'
            WHEN mpp.MachineProtocolTypeID = 25 THEN 'Fanuc Robotics'
            WHEN mpp.MachineProtocolTypeID = 26 THEN 'Modbus TCP'
            WHEN mpp.MachineProtocolTypeID = 27 THEN 'OPCClassic'
            WHEN mpp.MachineProtocolTypeID = 28 THEN 'Mazak'
            WHEN mpp.MachineProtocolTypeID = 29 THEN 'DirectHaas'
            WHEN mpp.MachineProtocolTypeID = 30 THEN 'TCP128-E'
            WHEN mpp.MachineProtocolTypeID = 31 THEN 'Heidenhain3'
            WHEN mpp.MachineProtocolTypeID = 32 THEN 'Mazak2'
            WHEN mpp.MachineProtocolTypeID = 33 THEN 'OmronFINS'
            WHEN mpp.MachineProtocolTypeID = 34 THEN 'ÁĎĎ'
            WHEN mpp.MachineProtocolTypeID = 35 THEN 'ŇÂÂ-11'
            WHEN mpp.MachineProtocolTypeID = 36 THEN 'TCP-V'
            WHEN mpp.MachineProtocolTypeID = 37 THEN 'SiemensNCK'
            ELSE 'íĺň äŕííűő'
        END as [Protocol],
        mon.PercentMonitoring,
        sig.PercentSignal,
        up.PercentUp
    FROM
        Machine m
        LEFT JOIN ProtocolInMachine pim ON m.ID = pim.MachineId
        LEFT JOIN MachineProtocol mpp ON pim.ProtocolId = mpp.ID
        JOIN (
            SELECT 
                MachineName,
                CAST((SUM(IIF(countdays = 0 OR countdays IS NULL, 0, 1)) * 1.00) / (COUNT(MachineParamName) * 1.00) AS NUMERIC(18,2)) as PercentMonitoring 
            FROM [dbo].[get_MonitoringSACHNoProtocol_data](@p_start_date, @p_end_date)
            GROUP BY MachineName
        ) mon ON (m.Name = mon.MachineName)
        JOIN (
            SELECT 
                MachineName,
                CAST((SUM(IIF(countdays = 0 OR countdays IS NULL, 0, 1)) * 1.00) / (COUNT(MachineParamName) * 1.00) AS NUMERIC(18,2)) as PercentSignal 
            FROM [dbo].[get_SignalSACHNoProtocol_data](@p_start_date, @p_end_date)
            GROUP BY MachineName
        ) sig ON (m.Name = sig.MachineName)
        JOIN (
            SELECT 
                MachineName,
                CAST((SUM(IIF(countcyclesup + countcyclessubroutineup = 0 OR (countcyclesup IS NULL AND countcyclessubroutineup IS NULL), 0, 1)) * 1.00) / (COUNT(MachineName) * 1.00) AS NUMERIC(18,2)) as PercentUp 
            FROM [dbo].[get_UPSACHNoProtocol_data](@p_start_date, @p_end_date)
            GROUP BY MachineName
        ) up ON (m.Name = up.MachineName)
)
GO
