  ---Ďđîöĺíň ďî ńîńňî˙íč˙ě č ďđč÷číŕě ďđîńňî˙

CREATE   FUNCTION [dbo].[get_MachineParamPercentSACHProtocol_data]
(
    @p_start_date DATETIME,
    @p_end_date DATETIME
)
RETURNS TABLE 
AS
RETURN 
(
    SELECT 
        ms.MachineParamName,
        mp.MachineParamTypeID,  -- Äîáŕâëĺíî ďîëĺ čç MachineParam
        CAST(
            COUNT(DISTINCT CASE WHEN ms.countdays != 0 OR ms.countdays IS NOT NULL THEN ms.MachineName END) * 1.00 / 
            COUNT(DISTINCT ms.MachineName) 
            AS NUMERIC(18, 2)
        ) AS PercentParam,
        (DATEDIFF(DAY, @p_start_date, @p_end_date) + 1) * COUNT(DISTINCT CASE WHEN (ms.countdays != 0 OR ms.countdays IS NOT NULL) AND ms.Protocol IN ('íĺčçâĺńňíűé ďđîňîęîë', 'Áŕëň-Ńčńňĺě', 'Fanuc', 'Ěŕ˙ę', 'Heidenhain', 'MTConnect', 'Heidennain2', 'HAAS', 'Mitsubishi', 'Universal', 'OPCUA', 'Fanuc Robotics', 'Modbus TCP', 'OPCClassic', 'Mazak', 'DirectHaas', 'Heidenhain3', 'Mazak2', 'SiemensNCK') THEN ms.MachineName END) AS totalprotocolcountdays,
        SUM(CASE WHEN ms.Protocol IN ('íĺčçâĺńňíűé ďđîňîęîë', 'Áŕëň-Ńčńňĺě', 'Fanuc', 'Ěŕ˙ę', 'Heidenhain', 'MTConnect', 'Heidennain2', 'HAAS', 'Mitsubishi', 'Universal', 'OPCUA', 'Fanuc Robotics', 'Modbus TCP', 'OPCClassic', 'Mazak', 'DirectHaas', 'Heidenhain3', 'Mazak2', 'SiemensNCK') THEN COALESCE(ms.countdays, 0) END) AS protocolcountdays,
        (DATEDIFF(DAY, @p_start_date, @p_end_date) + 1) * COUNT(DISTINCT CASE WHEN (ms.countdays != 0 OR ms.countdays IS NOT NULL) AND ms.Protocol IN ('ŇÂÂ', 'Đ-16', 'ŇĐ', 'ŇĐ-1', 'Đ-32', 'ŇÂÂ-10', 'TCP-64', 'ÂŃ-357', 'IFMVSXXX', 'Siemens PLC', 'SKFIMx', 'TCP128-E', 'OmronFINS', 'ÁĎĎ', 'ŇÂÂ-11', 'TCP-V') THEN ms.MachineName END) AS totalhardwarecountdays,
        SUM(CASE WHEN ms.Protocol IN ('ŇÂÂ', 'Đ-16', 'ŇĐ', 'ŇĐ-1', 'Đ-32', 'ŇÂÂ-10', 'TCP-64', 'ÂŃ-357', 'IFMVSXXX', 'Siemens PLC', 'SKFIMx', 'TCP128-E', 'OmronFINS', 'ÁĎĎ', 'ŇÂÂ-11', 'TCP-V') THEN COALESCE(ms.countdays, 0) END) AS hardwarecountdays,
        COUNT(DISTINCT CASE WHEN (ms.countdays != 0 OR ms.countdays IS NOT NULL) AND ms.Protocol IN ('íĺčçâĺńňíűé ďđîňîęîë', 'Áŕëň-Ńčńňĺě', 'Fanuc', 'Ěŕ˙ę', 'Heidenhain', 'MTConnect', 'Heidennain2', 'HAAS', 'Mitsubishi', 'Universal', 'OPCUA', 'Fanuc Robotics', 'Modbus TCP', 'OPCClassic', 'Mazak', 'DirectHaas', 'Heidenhain3', 'Mazak2', 'SiemensNCK') THEN ms.MachineName END) AS UseMachineProtocolCount,
        COUNT(DISTINCT CASE WHEN ms.Protocol IN ('íĺčçâĺńňíűé ďđîňîęîë', 'Áŕëň-Ńčńňĺě', 'Fanuc', 'Ěŕ˙ę', 'Heidenhain', 'MTConnect', 'Heidennain2', 'HAAS', 'Mitsubishi', 'Universal', 'OPCUA', 'Fanuc Robotics', 'Modbus TCP', 'OPCClassic', 'Mazak', 'DirectHaas', 'Heidenhain3', 'Mazak2', 'SiemensNCK') THEN ms.MachineName END) AS TotalUseMachineProtocolCount,
        COUNT(DISTINCT CASE WHEN ms.countdays != 0 OR ms.countdays IS NOT NULL THEN ms.MachineName END) AS UseMachineCount,
        COUNT(DISTINCT CASE WHEN (ms.countdays != 0 OR ms.countdays IS NOT NULL) AND ms.Protocol IN ('ŇÂÂ', 'Đ-16', 'ŇĐ', 'ŇĐ-1', 'Đ-32', 'ŇÂÂ-10', 'TCP-64', 'ÂŃ-357', 'IFMVSXXX', 'Siemens PLC', 'SKFIMx', 'TCP128-E', 'OmronFINS', 'ÁĎĎ', 'ŇÂÂ-11', 'TCP-V') THEN ms.MachineName END) AS UseMachineHardwareCount,
        COUNT(DISTINCT CASE WHEN ms.Protocol IN ('ŇÂÂ', 'Đ-16', 'ŇĐ', 'ŇĐ-1', 'Đ-32', 'ŇÂÂ-10', 'TCP-64', 'ÂŃ-357', 'IFMVSXXX', 'Siemens PLC', 'SKFIMx', 'TCP128-E', 'OmronFINS', 'ÁĎĎ', 'ŇÂÂ-11', 'TCP-V') THEN ms.MachineName END) AS TotalUseMachineHardwareCount,
        COUNT(DISTINCT ms.MachineName) AS TotalMachineCount
    FROM 
        [dbo].[get_MonitoringSACH_data](@p_start_date, @p_end_date) ms
    INNER JOIN [dbo].[MachineParam] mp ON mp.Name = ms.MachineParamName  -- Äîáŕâëĺíŕ ńâ˙çü
    GROUP BY 
        ms.MachineParamName, mp.MachineParamTypeID  -- Äîáŕâëĺíî ďîëĺ â GROUP BY
)
GO
