  ---Ďđîöĺíň ďî čçěĺđ˙ĺěűě ń ďđîňîęîëŕěč

CREATE   FUNCTION [dbo].[get_SignalPercentSACHProtocol_data]
(
    @p_start_date DATETIME,
    @p_end_date DATETIME
)
RETURNS TABLE 
AS
RETURN 
(
    SELECT 
        MachineParamName,
        CAST(
            COUNT(DISTINCT CASE WHEN countdays != 0.0000 THEN MachineName END) * 1.00 / 
            COUNT(DISTINCT MachineName) 
            AS NUMERIC(18, 2)
        ) AS PercentParam,
        (DATEDIFF(DAY, @p_start_date, @p_end_date) + 1) * COUNT(DISTINCT CASE WHEN (countdays != 0 OR countdays IS NOT NULL) AND Protocol IN ('íĺčçâĺńňíűé ďđîňîęîë', 'Áŕëň-Ńčńňĺě', 'Fanuc', 'Ěŕ˙ę', 'Heidenhain', 'MTConnect', 'Heidennain2', 'HAAS', 'Mitsubishi', 'Universal', 'OPCUA', 'Fanuc Robotics', 'Modbus TCP', 'OPCClassic', 'Mazak', 'DirectHaas', 'Heidenhain3', 'Mazak2', 'SiemensNCK') THEN MachineName END) AS totalprotocolcountdays,
        SUM(CASE WHEN Protocol IN ('íĺčçâĺńňíűé ďđîňîęîë', 'Áŕëň-Ńčńňĺě', 'Fanuc', 'Ěŕ˙ę', 'Heidenhain', 'MTConnect', 'Heidennain2', 'HAAS', 'Mitsubishi', 'Universal', 'OPCUA', 'Fanuc Robotics', 'Modbus TCP', 'OPCClassic', 'Mazak', 'DirectHaas', 'Heidenhain3', 'Mazak2', 'SiemensNCK') THEN COALESCE(countdays, 0) END) AS protocolcountdays,
        (DATEDIFF(DAY, @p_start_date, @p_end_date) + 1) * COUNT(DISTINCT CASE WHEN (countdays != 0 OR countdays IS NOT NULL) AND Protocol IN ('ŇÂÂ', 'Đ-16', 'ŇĐ', 'ŇĐ-1', 'Đ-32', 'ŇÂÂ-10', 'TCP-64', 'ÂŃ-357', 'IFMVSXXX', 'Siemens PLC', 'SKFIMx', 'TCP128-E', 'OmronFINS', 'ÁĎĎ', 'ŇÂÂ-11', 'TCP-V') THEN MachineName END) AS totalhardwarecountdays,
        SUM(CASE WHEN Protocol IN ('ŇÂÂ', 'Đ-16', 'ŇĐ', 'ŇĐ-1', 'Đ-32', 'ŇÂÂ-10', 'TCP-64', 'ÂŃ-357', 'IFMVSXXX', 'Siemens PLC', 'SKFIMx', 'TCP128-E', 'OmronFINS', 'ÁĎĎ', 'ŇÂÂ-11', 'TCP-V') THEN COALESCE(countdays, 0) END) AS hardwarecountdays,
        COUNT(DISTINCT CASE WHEN countdays != 0.0000 THEN MachineName END) AS UseMachineCount,
        COUNT(DISTINCT CASE WHEN (countdays != 0.0000) AND Protocol IN ('íĺčçâĺńňíűé ďđîňîęîë', 'Áŕëň-Ńčńňĺě', 'Fanuc', 'Ěŕ˙ę', 'Heidenhain', 'MTConnect', 'Heidennain2', 'HAAS', 'Mitsubishi', 'Universal', 'OPCUA', 'Fanuc Robotics', 'Modbus TCP', 'OPCClassic', 'Mazak', 'DirectHaas', 'Heidenhain3', 'Mazak2', 'SiemensNCK') THEN MachineName END) AS UseMachineProtocolCount,
        COUNT(DISTINCT CASE WHEN Protocol IN ('íĺčçâĺńňíűé ďđîňîęîë', 'Áŕëň-Ńčńňĺě', 'Fanuc', 'Ěŕ˙ę', 'Heidenhain', 'MTConnect', 'Heidennain2', 'HAAS', 'Mitsubishi', 'Universal', 'OPCUA', 'Fanuc Robotics', 'Modbus TCP', 'OPCClassic', 'Mazak', 'DirectHaas', 'Heidenhain3', 'Mazak2', 'SiemensNCK') THEN MachineName END) AS TotalUseMachineProtocolCount,
        COUNT(DISTINCT CASE WHEN (countdays != 0.0000) AND Protocol IN ('ŇÂÂ', 'Đ-16', 'ŇĐ', 'ŇĐ-1', 'Đ-32', 'ŇÂÂ-10', 'TCP-64', 'ÂŃ-357', 'IFMVSXXX', 'Siemens PLC', 'SKFIMx', 'TCP128-E', 'OmronFINS', 'ÁĎĎ', 'ŇÂÂ-11', 'TCP-V') THEN MachineName END) AS UseMachineHardwareCount,
        COUNT(DISTINCT CASE WHEN Protocol IN ('ŇÂÂ', 'Đ-16', 'ŇĐ', 'ŇĐ-1', 'Đ-32', 'ŇÂÂ-10', 'TCP-64', 'ÂŃ-357', 'IFMVSXXX', 'Siemens PLC', 'SKFIMx', 'TCP128-E', 'OmronFINS', 'ÁĎĎ', 'ŇÂÂ-11', 'TCP-V') THEN MachineName END) AS TotalUseMachineHardwareCount,
        COUNT(DISTINCT MachineName) AS TotalMachineCount
    FROM 
        [dbo].[get_SignalSACH_data](@p_start_date, @p_end_date)
    GROUP BY 
        MachineParamName
)
GO
