---Ďđîöĺíň ń ÓĎ

CREATE   FUNCTION [dbo].[get_UPPercentSACH_data]
(
    @p_start_date DATETIME,
    @p_end_date DATETIME
)
RETURNS TABLE 
AS
RETURN 
(
    SELECT 
        p.value AS Protocol,
        SUM(countcyclesup + countcyclessubroutineup) as TotalCountCycles,
        CAST(IIF(SUM(countsubroutineupinterrupted + countupinterrupted) = 0, 0, 
             SUM(countupsucces + countsubroutineupsucces) * 1.00 / SUM(countcyclesup + countcyclessubroutineup) * 1.00) AS NUMERIC(18,2)) as SuccesPercent,
        CAST(IIF(SUM(countsubroutineupinterrupted + countupinterrupted) = 0, 0, 
             SUM(countsubroutineupinterrupted + countupinterrupted) * 1.00 / SUM(countcyclesup + countcyclessubroutineup) * 1.00) AS NUMERIC(18,2)) as InterruptPercent
    FROM 
        (VALUES 
            ('íĺčçâĺńňíűé ďđîňîęîë'),
            ('Fanuc'),
            ('Ěŕ˙ę'),
            ('Heidenhain'),
            ('MTConnect'),
            ('IFMVSXXX'),
            ('Heidennain2'),
            ('HAAS'),
            ('Mitsubishi'),
            ('SKFIMx'),
            ('Universal'),
            ('OPCUA'),
            ('Fanuc Robotics'),
            ('Modbus TCP'),
            ('OPCClassic'),
            ('Mazak'),
            ('DirectHaas'),
            ('Heidenhain3'),
            ('Mazak2'),
            ('OmronFINS'),
            ('SiemensNCK')
        ) AS p (value)
    INNER JOIN [dbo].[get_UPSACH_data](@p_start_date, @p_end_date) us 
        ON p.value = us.Protocol
    GROUP BY p.value
)
GO
