SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[AssemblyUnit]
AS
SELECT i.Id,
	i.Code,
	i.[Name],
	i.[Description],
	i.AssemblyUnitTypeId,
	i.ItemGroupId AS AssemblyUnitGroupId,
	CASE i.[Status] WHEN 2 THEN CAST(1 AS BIT) ELSE CAST(0 AS BIT) END AS IsDeleted,
	i.IntegrationId,
	i.AttachedFilePathList,
	COALESCE(
		(SELECT TOP 1 s.Id FROM dbo.AssemblyUnitSpecification s WHERE s.AssemblyUnitId = i.Id AND s.IsDefault = 1 AND s.IsDeleted = 0),
		(SELECT TOP 1 s.Id FROM dbo.AssemblyUnitSpecification s WHERE s.AssemblyUnitId = i.Id AND s.IsDeleted = 0),
		(SELECT TOP 1 s.Id FROM dbo.AssemblyUnitSpecification s WHERE s.AssemblyUnitId = i.Id)) AS DefaultSpecificationId,
	i.RowAddDate,
	i.RowAddUser,
	i.RowUpdateDate,
	i.RowUpdateUser,
	i.DrawingNumber AS Article,
	i.UnitId AS MeasurementUnitId,
	i.ItemKindId
FROM dbo.Item i;
GO
