SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
create view [dbo].[ViewWorkerAnalitic] as
                SELECT rep.[MachineID]
                ,[CalcDate]
                ,[SmenaNum] as SheduleNumber
                ,[FromDate] as SheduleStartDateTime
                ,[ToDate] as SheduleFinishDateTime
                ,[SheduleTypeID] as ShedulePeriodTypeId
                ,[MachineParamId] as StateId
                ,[StateTime] as [StateTimeSeconds]
                ,convert(float, ([StateTime] * 1.0) / 3600.0) as [StateTimeHours]
                ,(select max(mpg.GroupParamID) from [dbo].[MachineParamInGroup] mpg where mpg.MachineParamID = rep.MachineParamID) as MainGroupParamId /* ďîńë ăđóďďŕ ďŕđŕěĺňđîâ */
                ,(select [Name] from GroupParam where GroupParam.ID = (select max(mpg.GroupParamID) from [dbo].[MachineParamInGroup] mpg where mpg.MachineParamID = rep.MachineParamID)) as MainGroupParamName /* ďîńë ăđóďďŕ ďŕđŕěĺňđîâ */
                ,(select [Name] from [Machine] where Machine.ID = rep.MachineID) as [MachineName]
                ,(select [ShortName] from [Machine] where Machine.ID = rep.MachineID) as [MachineShortName]
                ,(select [Name] from [MachineParam] where [MachineParam].ID = rep.[MachineParamID]) as [MachineParamName]
                ,(select [ShortName] from [MachineParam] where [MachineParam].ID = rep.[MachineParamID]) as [MachineParamShortName]
                ,(select d.[Name] from Dept d, Machine m where m.DeptID = d.ID and m.Id = rep.MachineID) as DeptName
                ,(select (select d2.[name] from Dept d2 where d2.ID = d.ParentID) as ParentName from Dept d, Machine m where m.DeptID = d.ID and m.Id = rep.MachineID) as DeptParentName
                , WorkerID
                ,(select Worker.LastName + ' ' + Worker.FirstName + ' ' + Worker.Patronymic from Worker where Worker.ID = rep.WorkerID) as WorkerName

                FROM [dbo].[rep_WorkerAnalitic] rep
                WHERE rep.CalcDate >= '2020-01-01'
                and SheduleTypeID = 1;
