/****** Object:  View [dbo].[ViewTechnologyOperationAnalitic]    Script Date: 17.02.2026 10:51:41 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
create view [dbo].[ViewTechnologyOperationAnalitic] as
                SELECT rep.[MachineId]
                ,[CalcDate]
                ,[MachineParamId]
                ,[ScheduleNum] as ShiftNumber
                ,[FromDate] as SheduleStartDateTime
                ,[ToDate] as SheduleFinishDateTime
                ,[ScheduleTypeId] as ShedulePeriodTypeId
                ,[ScopeTypeID] as ScopeTypeId
                ,[MadeCount] as MadeCount
                ,[BrakCount] as DefectCount
                ,[EnergoUse] as EnorgoUse
                ,[StateCount] as StateCount
                ,[PlanCount] as PlanCount
                ,[StateTime] as StateTime
                ,[FondTime] as FondTime
                ,convert(float, ([FondTime] * 1.0) / 3600.0) as [FondTimeHours]
                ,convert(float, ([StateTime] * 1.0) / 3600.0) as [StateTimeHours]
                ,(select [Name] from [Machine] where Machine.ID = rep.MachineId) as [MachineName]
                ,(select [ShortName] from [Machine] where Machine.ID = rep.MachineId) as [MachineShortName]
                ,(select d.[Name] from Dept d, Machine m where m.DeptID = d.ID and m.Id = rep.MachineId) as DeptName
                ,(select (select d2.[name] from Dept d2 where d2.ID = d.ParentID) as ParentName from Dept d, Machine m where m.DeptID = d.ID and m.Id = rep.MachineId) as DeptParentName
                ,(select max(mpg.GroupParamID) from [dbo].[MachineParamInGroup] mpg where mpg.MachineParamID = rep.MachineParamId) as MainGroupParamId/* ďîńë ăđóďďŕ ďŕđŕěĺňđîâ */
                ,(select [Name] from GroupParam where GroupParam.ID = (select max(mpg.GroupParamID) from [dbo].[MachineParamInGroup] mpg where mpg.MachineParamID = rep.MachineParamId)) as MainGroupParamName /* ďîńë ăđóďďŕ ďŕđŕěĺňđîâ */
                ,(select [Name] from [MachineParam] where [MachineParam].ID = rep.[MachineParamId]) as [MachineParamName] 
                ,(select [ShortName] from [MachineParam] where [MachineParam].ID = rep.[MachineParamId]) as [MachineParamShortName]
                ,(select Worker.LastName + ' ' + Worker.FirstName + ' ' + Worker.Patronymic from Worker where Worker.ID = rep.WorkerId) as WorkerName
                ,(select [Code] from [TechnologyOperation] where [TechnologyOperation].Id = rep.[TechnologyoperationId]) as [TechnologyOperationName]
                ,(select a.[Name] from AssemblyUnit a,  AssemblyUnitSpecification s where a.Id = s.AssemblyUnitId and s.Id = rep.TechnologyOperationId) as AssemblyUnitName
                ,(select a.[Code] from AssemblyUnit a,  AssemblyUnitSpecification s where a.Id = s.AssemblyUnitId and s.Id = rep.TechnologyOperationId) as AssemblyUnitCode
                ,(select [MachineTime] from [TechnologyOperation] where [TechnologyOperation].Id = rep.[TechnologyoperationId]) as [MachineTime]
                ,(select [PieceTime] from [TechnologyOperation] where [TechnologyOperation].Id = rep.[TechnologyoperationId]) as [PieceTime]
                ,(select [AdditionalTime] from [TechnologyOperation] where [TechnologyOperation].Id = rep.[TechnologyoperationId]) as [AdditionalTime]
                ,(select [PrepareTime] from [TechnologyOperation] where [TechnologyOperation].Id = rep.[TechnologyoperationId]) as [PrepareTime]

                FROM [dbo].rep_TechnologyOperationAnalitic rep
                WHERE rep.CalcDate >= '2020-01-01'
                and ScheduleTypeId = 1
