/****** Object:  StoredProcedure [dbo].[SP_AddjustManufacturingRouteSheetStatus]    Script Date: 17.02.2026 10:51:49 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		Oleg Osepyants
-- Create date: 10.10.2025
-- Description:	Addjusting the CurrentRouteSheetStatus and CurrentOperationStatus
-- =============================================
CREATE PROCEDURE [dbo].[SP_AddjustManufacturingRouteSheetStatus]
AS
BEGIN
	SET NOCOUNT ON;

	-- Addjusting the CurrentRouteSheetStatus
	UPDATE m
	SET CurrentRouteSheetStatus = s.RouteSheetStatus
	FROM ManufacturingRouteSheet m
		INNER JOIN ManufacturingRouteSheetStateHistory h ON h.Id = m.CurrentStateId
		INNER JOIN ManufacturingRouteSheetState s ON s.Id = h.ToStateId
	WHERE m.CurrentRouteSheetStatus <> s.RouteSheetStatus;

	UPDATE r
	SET CurrentRouteSheetStatus = 3
	FROM ManufacturingRouteSheet r
	WHERE r.CurrentRouteSheetStatus NOT IN (0,1,3)
		AND EXISTS
		(
			SELECT TOP 1 1
			FROM ManufacturingRouteSheet c
			WHERE c.InitialId = r.Id
		);

	-- Distributing the CurrentRouteSheetStatus
	UPDATE r
	SET CurrentRouteSheetStatus = m.CurrentRouteSheetStatus
	FROM ManufacturingRouteSheet m
		INNER JOIN ManufacturingAnalyticAssignment r ON r.ManufacturingRouteSheetId = m.Id
	WHERE r.CurrentRouteSheetStatus <> m.CurrentRouteSheetStatus;

	UPDATE ManufacturingAnalyticAssignment
	SET CurrentRouteSheetStatus = 0
	WHERE ManufacturingRouteSheetId IS NULL;

	UPDATE r
	SET CurrentRouteSheetStatus = m.CurrentRouteSheetStatus
	FROM ManufacturingRouteSheet m
		INNER JOIN FileInManufacturingRouteSheet r ON r.ManufacturingRouteSheetId = m.Id
	WHERE r.CurrentRouteSheetStatus <> m.CurrentRouteSheetStatus;

	UPDATE r
	SET CurrentRouteSheetStatus = m.CurrentRouteSheetStatus
	FROM ManufacturingRouteSheet m
		INNER JOIN ManufacturingOperation r ON r.ManufacturingRouteSheetId = m.Id
	WHERE r.CurrentRouteSheetStatus <> m.CurrentRouteSheetStatus;

	UPDATE r
	SET CurrentRouteSheetStatus = m.CurrentRouteSheetStatus
	FROM ManufacturingRouteSheet m
		INNER JOIN ManufacturingOperationSequence r ON r.ManufacturingRouteSheetId = m.Id
	WHERE r.CurrentRouteSheetStatus <> m.CurrentRouteSheetStatus;

	UPDATE r
	SET CurrentRouteSheetStatus = m.CurrentRouteSheetStatus
	FROM ManufacturingRouteSheet m
		INNER JOIN ManufacturingRouteSheetStateHistory r ON r.ManufacturingRouteSheetId = m.Id
	WHERE r.CurrentRouteSheetStatus <> m.CurrentRouteSheetStatus;

	UPDATE r
	SET CurrentRouteSheetStatus = m.CurrentRouteSheetStatus
	FROM ManufacturingAnalyticAssignment m
		INNER JOIN ManufacturingAnalytic r ON r.Id = m.AnalyticId
	WHERE r.CurrentRouteSheetStatus <> m.CurrentRouteSheetStatus;

	-- Addjusting the CurrentOperationStatus
	UPDATE m
	SET CurrentOperationStatus = CASE m.CurrentRouteSheetStatus
			WHEN 2 THEN 3
			WHEN 4 THEN 7
			WHEN 5 THEN 8
			WHEN 6 THEN 9
			ELSE s.OperationStatus
		END
	FROM ManufacturingOperation m
		INNER JOIN ManufacturingOperationStateHistory h ON h.Id = m.CurrentStateId
		INNER JOIN ManufacturingOperationState s ON s.Id = h.ToStateId;

	-- Distributing the CurrentOperationStatus
	UPDATE r
	SET CurrentOperationStatus = m.CurrentOperationStatus
	FROM ManufacturingOperation m
		INNER JOIN FileInManufacturingOperation r ON r.ManufacturingOperationId = m.Id
	WHERE r.CurrentOperationStatus <> m.CurrentOperationStatus;

	UPDATE r
	SET CurrentOperationStatus = m.CurrentOperationStatus
	FROM ManufacturingOperation m
		INNER JOIN ManufacturingOperationEquipmentPosition r ON r.ManufacturingOperationId = m.Id
	WHERE r.CurrentOperationStatus <> m.CurrentOperationStatus;

	UPDATE r
	SET CurrentOperationStatus = m.CurrentOperationStatus
	FROM ManufacturingOperation m
		INNER JOIN ManufacturingOperationExecutor r ON r.ManufacturingOperationId = m.Id
	WHERE r.CurrentOperationStatus <> m.CurrentOperationStatus;

	UPDATE r
	SET CurrentOperationStatus = m.CurrentOperationStatus
	FROM ManufacturingOperation m
		INNER JOIN ManufacturingOperationLabourPosition r ON r.ManufacturingOperationId = m.Id
	WHERE r.CurrentOperationStatus <> m.CurrentOperationStatus;

	UPDATE r
	SET CurrentOperationStatus = m.CurrentOperationStatus
	FROM ManufacturingOperation m
		INNER JOIN ManufacturingOperationMachineParam r ON r.ManufacturingOperationId = m.Id
	WHERE r.CurrentOperationStatus <> m.CurrentOperationStatus;

	UPDATE r
	SET CurrentOperationStatus = m.CurrentOperationStatus
	FROM ManufacturingOperation m
		INNER JOIN ManufacturingOperationStateHistory r ON r.ManufacturingOperationId = m.Id
	WHERE r.CurrentOperationStatus <> m.CurrentOperationStatus;

	UPDATE r
	SET CurrentOperationStatus = m.CurrentOperationStatus
	FROM ManufacturingOperation m
		INNER JOIN RecordOfPerformedWork r ON r.ManufacturingOperationId = m.Id
	WHERE r.CurrentOperationStatus <> m.CurrentOperationStatus;

	UPDATE r
	SET CurrentOperationStatus = CASE
			WHEN mo.CurrentOperationStatus IN (3,7,8,9) THEN mo.CurrentOperationStatus
			ELSE mf.CurrentOperationStatus
		END
	FROM SubmissionOnOperation r
		INNER JOIN ManufacturingOperation mf ON r.ManufacturingOperationFromId = mf.Id
		INNER JOIN ManufacturingOperation mo ON r.ManufacturingOperationOnId = mo.Id;

	UPDATE r
	SET CurrentOperationStatus = m.CurrentOperationStatus
	FROM ManufacturingOperation m
		INNER JOIN RecordOfPerformedWorkExecutorRegistration r ON r.ManufacturingOperationId = m.Id
	WHERE r.CurrentOperationStatus <> m.CurrentOperationStatus;

	UPDATE r
	SET CurrentOperationStatus = m.CurrentOperationStatus
	FROM ManufacturingOperation m
		INNER JOIN ShiftTaskPosition r ON r.ManufacturingOperationId = m.Id
	WHERE r.CurrentOperationStatus <> m.CurrentOperationStatus;

	UPDATE r
	SET CurrentOperationStatus = m.CurrentOperationStatus
	FROM RecordOfPerformedWork m
		INNER JOIN RecordOfPerformedWorkExecutor r ON r.RecordOfPerformedWorkId = m.Id
	WHERE r.CurrentOperationStatus <> m.CurrentOperationStatus;

	UPDATE r
	SET CurrentOperationStatus = m.CurrentOperationStatus
	FROM RecordOfPerformedWork m
		INNER JOIN RecordOfItemQtyProcessed r ON (r.RecordOfPerformedWorkId = m.Id OR r.RecordOfConfirmedWorkId = m.Id)
	WHERE r.CurrentOperationStatus <> m.CurrentOperationStatus;

	UPDATE r
	SET CurrentOperationStatus = m.CurrentOperationStatus
	FROM SubmissionOnOperation m
		INNER JOIN SubmissionOnOperationSerialNumber r ON r.SubmissionOnOperationId = m.Id
	WHERE r.CurrentOperationStatus <> m.CurrentOperationStatus;

	UPDATE r
	SET CurrentOperationStatus = m.CurrentOperationStatus
	FROM ShiftTaskPosition m
		INNER JOIN ShiftTaskPositionExecutor r ON r.ShiftTaskPositionId = m.Id
	WHERE r.CurrentOperationStatus <> m.CurrentOperationStatus;

	UPDATE r
	SET CurrentOperationStatus = m.CurrentOperationStatus
	FROM ManufacturingOperation m
		INNER JOIN ManufacturingOperationMaterialPosition r ON r.ManufacturingOperationId = m.Id
	WHERE r.CurrentOperationStatus <> m.CurrentOperationStatus;
END

GO
