CREATE   PROCEDURE [dbo].[sp_get_MachineParamPercentSACH_data]
    @p_start_date DATETIME,
    @p_end_date DATETIME
AS
BEGIN
    SET NOCOUNT ON;
    
    SELECT 
        MachineParamName,
        PercentParam,
        UseMachineCount,
        TotalMachineCount
    FROM [dbo].[get_MachineParamPercentSACH_data](@p_start_date, @p_end_date)
    ORDER BY PercentParam DESC, MachineParamName
END
